#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    int n,a[102];
    cin>>n;
    for(int i=n;i>=0;i--)
        cin>>a[i];
    bool head=true;
    for(int i=n;i>=0;i--){
        if(!a[i])
            continue;
        if(a[i]>0){
            if(!head)
                cout<<'+';
            if(a[i]>1 || i==0)
            	cout<<a[i];
            if(i>0){
                cout<<"x";
                if(i>1)
                	cout<<"^"<<i;
            }
        }else{
        	cout<<'-';
        	a[i]=-a[i];
        	if(a[i]>1 || i==0)
            	cout<<a[i];
            if(i>0){
                cout<<"x";
                if(i>1)
                	cout<<"^"<<i;
            }
        }
        head=false;
    }
    return 0;
}
